import path from"node:path";const isWin="win32"===process.platform;export const isAbsolute=path.isAbsolute;export const dirname=path.posix.dirname;export const extname=path.posix.extname;export const basename=path.posix.basename;export const join=path.posix.join;export const toPosix=isWin?t=>t.split(path.sep).join(path.posix.sep):t=>t;export const resolve=path.posix.resolve;export const relative=(t,o)=>{if(o.startsWith(t)){const s=o[t.length];if("/"===s)return o.substring(t.length+1);if(void 0===s)return"."}const s=path.relative(t,o);return isWin?toPosix(s):s||"."};export const isInNodeModules=t=>t.includes("node_modules");export const toAbsolute=(t,o)=>isAbsolute(t)?t:join(o,t);export const toRelative=(t,o)=>isAbsolute(t)?relative(o,t):t;export const isInternal=t=>(t.startsWith(".")||isAbsolute(t))&&!isInNodeModules(t);export const normalize=path.posix.normalize;